module RefModule (
    input clk,
    input load,
    input en,
    input [12:0] d,
    output [12:0] q
);

    reg [12:0] unused_q_reg;

    always @(posedge clk or posedge load) begin
        if (load)
            unused_q_reg <= d;
        else if (en)
            unused_q_reg <= unused_q_reg + 1;
    end

    assign q = unused_q_reg;

endmodule
